INSERT INTO Questions (original_id, discipline, question, options, answer, explanation, banca, pegadinha, content_id) VALUES ('14', 'Português', 'Assinale a alternativa em que o termo entre parênteses **não** corresponde a uma figura de linguagem presente no trecho:', '[{"letra":"A","texto":"*\"A rigidez excessiva... pode converter-se em obstáculo intransponível.\"* (Metáfora)","correta":false},{"letra":"B","texto":"*\"O ponto de equilíbrio, ainda que movediço, reside na gestão orientada por resultados.\"* (Antítese)","correta":true},{"letra":"C","texto":"*\"A administração pública, em sua busca incessante pela eficiência...\"* (Prosopopeia)","correta":false},{"letra":"D","texto":"*\"O servidor é uma formiga trabalhando.\"* (Comparação)","correta":false},{"letra":"E","texto":"*\"Sua boca é um sepulcro.\"* (Metáfora)","correta":false}]', 'B', 'De acordo com a regra gramatical e coerência textual, a resolução aponta para a alternativa correta: **"*"O ponto de equilíbrio, ainda que movediço, reside na gestão orientada por resultados."* (Antítese)"**.

Verifique as palavras-chave que conectam o enunciado à resposta e anule alternativas que distorçam o conhecimento aplicado.', 'ESAF', 'A ESAF tem a tradição de usar textos densos ou alternativas com ''cascas de banana'', alterando apenas verbos ou advérbios restritivos (como ''somente'', ''sempre'', ''nunca''). Leia os distratores com atenção!', 1);
INSERT INTO Questions (original_id, discipline, question, options, answer, explanation, banca, pegadinha, content_id) VALUES ('15', 'Português', 'De acordo com o Manual de Redação da Presidência da República, a comunicação interna entre unidades de um mesmo órgão público deve ser feita por meio de:', '[{"letra":"A","texto":"Ofício","correta":true},{"letra":"B","texto":"Aviso","correta":false},{"letra":"C","texto":"Memorando","correta":false},{"letra":"D","texto":"Mensagem","correta":false},{"letra":"E","texto":"Exposição de Motivos","correta":false}]', 'A', '[GABARITO CORRIGIDO] Segundo a 3ª edição do Manual de Redação da Presidência da República (2018), os padrões ''Memorando'' e ''Aviso'' foram abolidos. Toda comunicação oficial (seja interna ou externa) agora utiliza o padrão único chamado **Ofício**.', 'ESAF', 'Bancas usam material antigo para confundir alunos sobre o finado ''Memorando''. Memorize a extinção dele pelo MRPR de 2018.', 1);
