INSERT INTO Questions (original_id, discipline, question, options, answer, explanation, banca, pegadinha, content_id) VALUES ('61', 'Regime Jurídico', 'O servidor público federal adquire estabilidade após:', '[{"letra":"A","texto":"2 anos de efetivo exercício, independentemente de avaliação.","correta":false},{"letra":"B","texto":"2 anos de efetivo exercício e aprovação em estágio probatório.","correta":false},{"letra":"C","texto":"3 anos de efetivo exercício e aprovação em avaliação especial de desempenho.","correta":true},{"letra":"D","texto":"3 anos de efetivo exercício, contados da posse.","correta":false},{"letra":"E","texto":"5 anos de efetivo exercício, comprovada a capacidade.","correta":false}]', 'C', 'De acordo com a literalidade da lei (ex. Lei 8.112/90) aliada à jurisprudência atual, a resolução aponta para a alternativa correta: **"3 anos de efetivo exercício e aprovação em avaliação especial de desempenho."**.

Verifique as palavras-chave que conectam o enunciado à resposta e anule alternativas que distorçam o conhecimento aplicado.', 'ESAF', 'A ESAF tem a tradição de usar textos densos ou alternativas com ''cascas de banana'', alterando apenas verbos ou advérbios restritivos (como ''somente'', ''sempre'', ''nunca''). Leia os distratores com atenção!', 1);
INSERT INTO Questions (original_id, discipline, question, options, answer, explanation, banca, pegadinha, content_id) VALUES ('62', 'Regime Jurídico', 'O retorno à atividade do servidor aposentado por invalidez, quando insubsistentes os motivos da aposentadoria, é denominado:', '[{"letra":"A","texto":"Reintegração.","correta":false},{"letra":"B","texto":"Recondução.","correta":false},{"letra":"C","texto":"Readaptação.","correta":false},{"letra":"D","texto":"Aproveitamento.","correta":false},{"letra":"E","texto":"Reversão.","correta":true}]', 'E', 'De acordo com a literalidade da lei (ex. Lei 8.112/90) aliada à jurisprudência atual, a resolução aponta para a alternativa correta: **"Reversão."**.

Verifique as palavras-chave que conectam o enunciado à resposta e anule alternativas que distorçam o conhecimento aplicado.', 'ESAF', 'A ESAF tem a tradição de usar textos densos ou alternativas com ''cascas de banana'', alterando apenas verbos ou advérbios restritivos (como ''somente'', ''sempre'', ''nunca''). Leia os distratores com atenção!', 1);
INSERT INTO Questions (original_id, discipline, question, options, answer, explanation, banca, pegadinha, content_id) VALUES ('63', 'Regime Jurídico', 'Constitui **proibição** ao servidor público (Lei nº 8.112/1990):', '[{"letra":"A","texto":"Participar da administração de empresa privada, mesmo sem prejuízo de suas funções.","correta":true},{"letra":"B","texto":"Atender com presteza ao público, fornecendo as certidões requeridas.","correta":false},{"letra":"C","texto":"Exercer o direito de greve, nos termos da lei específica.","correta":false},{"letra":"D","texto":"Representar contra ilegalidade ou abuso de poder.","correta":false},{"letra":"E","texto":"Ser leal às instituições a que servir.","correta":false}]', 'A', 'De acordo com a literalidade da lei (ex. Lei 8.112/90) aliada à jurisprudência atual, a resolução aponta para a alternativa correta: **"Participar da administração de empresa privada, mesmo sem prejuízo de suas funções."**.

Verifique as palavras-chave que conectam o enunciado à resposta e anule alternativas que distorçam o conhecimento aplicado.

💡 **Dica Extra:** Prazos, penalidades graves (demissão e cassação) e formas de provimento garantem a maioria das questões desse Título na Lei 8.112/90.', 'ESAF', 'A ESAF tem a tradição de usar textos densos ou alternativas com ''cascas de banana'', alterando apenas verbos ou advérbios restritivos (como ''somente'', ''sempre'', ''nunca''). Leia os distratores com atenção!', 1);
