INSERT INTO Questions (original_id, discipline, question, options, answer, explanation, banca, pegadinha, content_id) VALUES ('65', 'Regime Jurídico', 'O servidor estável demitido por processo administrativo disciplinar poderá ser **reintegrado** ao cargo se:', '[{"letra":"A","texto":"Completar 5 anos de afastamento.","correta":false},{"letra":"B","texto":"A demissão for considerada nula por decisão administrativa ou judicial.","correta":true},{"letra":"C","texto":"O Presidente da República determinar sua reintegração.","correta":false},{"letra":"D","texto":"Houver vacância no cargo anterior.","correta":false},{"letra":"E","texto":"A sindicância que originou o processo for arquivada.","correta":false}]', 'B', 'De acordo com a literalidade da lei (ex. Lei 8.112/90) aliada à jurisprudência atual, a resolução aponta para a alternativa correta: **"A demissão for considerada nula por decisão administrativa ou judicial."**.

