INSERT INTO Questions (original_id, discipline, question, options, answer, explanation, banca, pegadinha, content_id) VALUES ('66', 'Regime Jurídico', 'A lei que estabelece normas de conduta para agentes públicos e prevê sanções para atos de improbidade administrativa é a:', '[{"letra":"A","texto":"Lei nº 8.112/1990.","correta":false},{"letra":"B","texto":"Lei nº 9.784/1999.","correta":false},{"letra":"C","texto":"Lei nº 8.429/1992.","correta":true},{"letra":"D","texto":"Lei Complementar nº 101/2000.","correta":false},{"letra":"E","texto":"Decreto-Lei nº 2.848/1940.","correta":false}]', 'C', 'De acordo com a literalidade da lei (ex. Lei 8.112/90) aliada à jurisprudência atual, a resolução aponta para a alternativa correta: **"Lei nº 8.429/1992."**.

Verifique as palavras-chave que conectam o enunciado à resposta e anule alternativas que distorçam o conhecimento aplicado.', 'ESAF', 'A ESAF tem a tradição de usar textos densos ou alternativas com ''cascas de banana'', alterando apenas verbos ou advérbios restritivos (como ''somente'', ''sempre'', ''nunca''). Leia os distratores com atenção!', 1);
INSERT INTO Questions (original_id, discipline, question, options, answer, explanation, banca, pegadinha, content_id) VALUES ('67', 'Regime Jurídico', 'Constitui ato de improbidade administrativa que **causa prejuízo ao erário**:', '[{"letra":"A","texto":"Receber vantagem econômica para praticar ato de ofício.","correta":false},{"letra":"B","texto":"Praticar ato visando a fim diverso do previsto na regra de competência.","correta":false},{"letra":"C","texto":"Revelar fato de que tem ciência em razão do cargo, sem justa causa.","correta":false},{"letra":"D","texto":"Permitir que outrem utilize bem público para fins particulares.","correta":true},{"letra":"E","texto":"Adquirir, para si, bens incompatíveis com a sua renda.","correta":false}]', 'D', 'De acordo com a literalidade da lei (ex. Lei 8.112/90) aliada à jurisprudência atual, a resolução aponta para a alternativa correta: **"Permitir que outrem utilize bem público para fins particulares."**.

Verifique as palavras-chave que conectam o enunciado à resposta e anule alternativas que distorçam o conhecimento aplicado.', 'ESAF', 'A ESAF tem a tradição de usar textos densos ou alternativas com ''cascas de banana'', alterando apenas verbos ou advérbios restritivos (como ''somente'', ''sempre'', ''nunca''). Leia os distratores com atenção!', 1);
INSERT INTO Questions (original_id, discipline, question, options, answer, explanation, banca, pegadinha, content_id) VALUES ('68', 'Regime Jurídico', 'A licença ao servidor para tratar de **interesses particulares**:', '[{"letra":"A","texto":"É concedida com remuneração, por até 2 anos.","correta":false},{"letra":"B","texto":"Poderá ser concedida a qualquer tempo, independentemente do tempo de serviço.","correta":false},{"letra":"C","texto":"Não pode ser concedida ao servidor em estágio probatório.","correta":false},{"letra":"D","texto":"Poderá ser concedida por até 3 anos, sem remuneração.","correta":true},{"letra":"E","texto":"É concedida, automaticamente, por 1 ano, prorrogável por mais 1.","correta":false}]', 'D', 'De acordo com a literalidade da lei (ex. Lei 8.112/90) aliada à jurisprudência atual, a resolução aponta para a alternativa correta: **"Poderá ser concedida por até 3 anos, sem remuneração."**.

Verifique as palavras-chave que conectam o enunciado à resposta e anule alternativas que distorçam o conhecimento aplicado.', 'ESAF', 'A ESAF tem a tradição de usar textos densos ou alternativas com ''cascas de banana'', alterando apenas verbos ou advérbios restritivos (como ''somente'', ''sempre'', ''nunca''). Leia os distratores com atenção!', 1);
INSERT INTO Questions (original_id, discipline, question, options, answer, explanation, banca, pegadinha, content_id) VALUES ('69', 'Regime Jurídico', 'A perda do cargo público por servidor estável pode ocorrer em razão de decisão judicial transitada em julgado, processo administrativo disciplinar, ou ainda por meio de:', '[{"letra":"A","texto":"Avaliação periódica de desempenho, na forma de lei complementar.","correta":true},{"letra":"B","texto":"Exoneração a pedido do próprio servidor.","correta":false},{"letra":"C","texto":"Posse em outro cargo inacumulável.","correta":false},{"letra":"D","texto":"Aposentadoria voluntária.","correta":false},{"letra":"E","texto":"Promoção na carreira.","correta":false}]', 'A', 'De acordo com a literalidade da lei (ex. Lei 8.112/90) aliada à jurisprudência atual, a resolução aponta para a alternativa correta: **"Avaliação periódica de desempenho, na forma de lei complementar."**.

